using System;
using System.Collections.Generic;
using System.Linq;
using SensCalibr8.Data.Persistence;

namespace SensCalibr8.Data.Repositories
{
    public sealed class ScientificRigorRepository
    {
        private readonly RepositoryExecution execution;
        public ScientificRigorRepository(SqliteConnectionFactory factory,IDataFailureReporter reporter=null){execution=new RepositoryExecution(factory,reporter);}
        public long PersistOutlierRun(OutlierAnalysisRunRecord run)
        {
            if(run==null)throw new ArgumentNullException(nameof(run));return execution.Write("persist outlier analysis",connection=>
            {using SqliteTransaction transaction=connection.BeginImmediateTransaction();VerifyRunLineage(connection,run);var keys=new HashSet<string>(StringComparer.Ordinal);foreach(OutlierAuditObservationRecord value in run.Observations){string key=value.Kind+":"+value.ObservationId;if(!keys.Add(key))throw new InvalidOperationException("Outlier observations must be unique within one pass.");VerifyObservation(connection,run,value);}
                int flagged=run.Observations.Count(value=>value.IsStatisticalOutlier);connection.Execute(@"INSERT INTO outlier_analysis_runs(profile_id,cycle_id,calibration_config_id,phase,mode,sensitivity_value,metric_name,scope_key,group_mean,sample_sd,threshold_value,inclusive_mean,flagged_excluded_mean,observation_count,flagged_count,algorithm_version)
VALUES(@profile,@cycle,@config,@phase,@mode,@sensitivity,@metric,@scope,@mean,@sd,@threshold,@inclusive,@excluded,@count,@flagged,@algorithm);",new Dictionary<string,object>{{"@profile",run.ProfileId},{"@cycle",run.CycleId},{"@config",run.CalibrationConfigId},{"@phase",run.Phase},{"@mode",run.Mode},{"@sensitivity",run.SensitivityValue},{"@metric",run.MetricName},{"@scope",run.ScopeKey},{"@mean",run.GroupMean},{"@sd",run.SampleSd},{"@threshold",run.ThresholdValue},{"@inclusive",run.InclusiveMean},{"@excluded",run.FlaggedExcludedMean},{"@count",run.Observations.Count},{"@flagged",flagged},{"@algorithm",run.AlgorithmVersion}});long runId=connection.LastInsertRowId();
                foreach(OutlierAuditObservationRecord value in run.Observations){if(value.Kind==OutlierAuditObservationKind.Shot)connection.Execute("UPDATE shots SET is_outlier=COALESCE(is_outlier,0) WHERE id=@id;",new Dictionary<string,object>{{"@id",value.ObservationId}});if(!value.IsStatisticalOutlier)continue;connection.Execute(@"INSERT INTO outlier_flags(session_id,shot_id,tracking_data_id,metric_name,scope_key,observed_value,group_mean,sample_sd,threshold_value,algorithm_version,is_statistical_outlier,is_data_quality_error,excluded_from_authoritative_score,disposition_reason,analysis_run_id)
VALUES(@session,@shot,@tracking,@metric,@scope,@observed,@mean,@sd,@threshold,@algorithm,1,0,0,'statistical-flag-included',@run);",new Dictionary<string,object>{{"@session",value.SessionId},{"@shot",value.Kind==OutlierAuditObservationKind.Shot?(object)value.ObservationId:null},{"@tracking",value.Kind==OutlierAuditObservationKind.TrackingTrial?(object)value.ObservationId:null},{"@metric",run.MetricName},{"@scope",run.ScopeKey},{"@observed",value.ObservedValue},{"@mean",run.GroupMean},{"@sd",run.SampleSd},{"@threshold",run.ThresholdValue},{"@algorithm",run.AlgorithmVersion},{"@run",runId}});if(value.Kind==OutlierAuditObservationKind.Shot)connection.Execute("UPDATE shots SET is_outlier=1 WHERE id=@id;",new Dictionary<string,object>{{"@id",value.ObservationId}});}
                transaction.Commit();return runId;});
        }
        public void ConfirmDataQualityExclusion(long flagId,string documentedReason)
        {if(flagId<=0)throw new ArgumentOutOfRangeException(nameof(flagId));if(string.IsNullOrWhiteSpace(documentedReason))throw new ArgumentException("A documented data-quality reason is required.",nameof(documentedReason));execution.Write("confirm data-quality exclusion",connection=>{int changed=connection.Execute("UPDATE outlier_flags SET is_data_quality_error=1,excluded_from_authoritative_score=1,disposition_reason=@reason WHERE id=@id AND is_statistical_outlier=1 AND is_data_quality_error=0 AND excluded_from_authoritative_score=0;",new Dictionary<string,object>{{"@reason",documentedReason},{"@id",flagId}});if(changed!=1)throw new InvalidOperationException("Outlier flag cannot be excluded without a separate unconfirmed statistical flag.");return 0;});}
        public void ApplyFatigue(long sessionId,double? declinePercent,bool flagged,string algorithmVersion)
        {if(sessionId<=0)throw new ArgumentOutOfRangeException(nameof(sessionId));if(string.IsNullOrWhiteSpace(algorithmVersion))throw new ArgumentException(nameof(algorithmVersion));execution.Write("apply fatigue audit",connection=>{object ready=connection.Scalar(@"SELECT COUNT(*) FROM sessions s WHERE s.id=@id AND s.fatigue_score_change_percentage IS NULL AND s.fatigue_algorithm_version IS NULL AND ((s.mode='tracking' AND NOT EXISTS(SELECT 1 FROM tracking_data t WHERE t.session_id=s.id AND t.is_adaptation_trial IS NULL)) OR (s.mode<>'tracking' AND NOT EXISTS(SELECT 1 FROM shots sh WHERE sh.session_id=s.id AND sh.is_adaptation_shot IS NULL)));",new Dictionary<string,object>{{"@id",sessionId}});if(Convert.ToInt64(ready)!=1)throw new InvalidOperationException("Fatigue may be applied exactly once after adaptation finalization.");connection.Execute("UPDATE sessions SET fatigue_score_change_percentage=@change,fatigue_flag=@flag,fatigue_algorithm_version=@version WHERE id=@id;",new Dictionary<string,object>{{"@change",declinePercent},{"@flag",flagged},{"@version",algorithmVersion},{"@id",sessionId}});return 0;});}
        public void ApplyGrade(long sensitivityTestId,GradeAuditRecord grade)
        {if(sensitivityTestId<=0)throw new ArgumentOutOfRangeException(nameof(sensitivityTestId));if(grade==null)throw new ArgumentNullException(nameof(grade));execution.Write("apply grade audit",connection=>{int changed=connection.Execute(@"UPDATE sensitivity_tests SET grade=@grade,grade_contract_version=@version,reaction_tier=@reaction,consistency_tier=@consistency,close_reaction_time_ms=@reaction_ms,battery_consistency_utility=@utility WHERE id=@id AND grade IS NULL AND grade_contract_version IS NULL;",new Dictionary<string,object>{{"@grade",grade.FinalGrade},{"@version",grade.ContractVersion},{"@reaction",grade.ReactionTier},{"@consistency",grade.ConsistencyTier},{"@reaction_ms",grade.CloseReactionTimeMs},{"@utility",grade.BatteryConsistencyUtility},{"@id",sensitivityTestId}});if(changed!=1)throw new InvalidOperationException("Grade may be assigned exactly once to an existing sensitivity test.");return 0;});}
        private static void VerifyRunLineage(SqliteDatabaseConnection connection,OutlierAnalysisRunRecord run){object count=connection.Scalar("SELECT COUNT(*) FROM cycles c JOIN calibration_configs cfg ON cfg.id=@config WHERE c.id=@cycle AND c.profile_id=@profile;",new Dictionary<string,object>{{"@config",run.CalibrationConfigId},{"@cycle",run.CycleId},{"@profile",run.ProfileId}});if(Convert.ToInt64(count)!=1)throw new InvalidOperationException("Outlier run lineage is invalid.");}
        private static void VerifyObservation(SqliteDatabaseConnection connection,OutlierAnalysisRunRecord run,OutlierAuditObservationRecord value)
        {string table=value.Kind==OutlierAuditObservationKind.Shot?"shots":"tracking_data",adaptation=value.Kind==OutlierAuditObservationKind.Shot?"is_adaptation_shot":"is_adaptation_trial",expression=ObservedExpression(value.Kind,run.MetricName);object count=connection.Scalar("SELECT COUNT(*) FROM "+table+" o JOIN sessions s ON s.id=o.session_id JOIN protocol_batteries b ON b.id=s.battery_id WHERE o.id=@observation AND s.id=@session AND s.profile_id=@profile AND s.calibration_config_id=@config AND s.mode=@mode AND b.cycle_id=@cycle AND b.phase=@phase AND b.sensitivity_value=@sensitivity AND o."+adaptation+"=0 AND "+expression+"=@observed;",new Dictionary<string,object>{{"@observation",value.ObservationId},{"@session",value.SessionId},{"@profile",run.ProfileId},{"@config",run.CalibrationConfigId},{"@mode",run.Mode},{"@cycle",run.CycleId},{"@phase",run.Phase},{"@sensitivity",run.SensitivityValue},{"@observed",value.ObservedValue}});if(Convert.ToInt64(count)!=1)throw new InvalidOperationException("Outlier observation is outside the homogeneous post-adaptation scope or does not match raw evidence.");}
        private static string ObservedExpression(OutlierAuditObservationKind kind,string metric)
        {if(kind==OutlierAuditObservationKind.Shot){switch(metric){case "final_precision_error_deg":return "o.final_precision_error";case "submovement_count":return "o.submovement_count";case "reaction_time_ms":case "correction_time_ms":return "(o.resolution_timestamp-o.spawn_timestamp)*1000.0";case "travel_time_ms":return "(o.resolution_timestamp-o.first_mouse_movement_timestamp)*1000.0";default:throw new InvalidOperationException("Unsupported shot outlier metric: "+metric);}}switch(metric){case "tracking_deviation_rms_deg":return "(SELECT AVG(w.tracking_deviation_rms_deg) FROM tracking_windows w WHERE w.tracking_trial_id=o.id)";case "time_on_target_percent":return "o.time_on_target_percentage";default:throw new InvalidOperationException("Unsupported Tracking outlier metric: "+metric);}}
    }
}
